import { unstable_cache } from 'next/cache'

export type Post = {
  id: number
  title: string
  body: string
}

const store: Post[] = [
  { id: 1, title: 'First Post', body: 'This is the first post.' },
  { id: 2, title: 'Second Post', body: 'This is the second post.' },
]

/**
 * Returns all posts, cached with the "posts" tag so it can be invalidated
 * on demand via revalidateTag("posts").
 */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => {
    return [...store]
  },
  ['posts-list'],
  { tags: ['posts'] },
)

/**
 * Adds a new post to the in-memory store.
 */
export function addPost(title: string, body: string): Post {
  const id = store.length + 1
  const post: Post = { id, title, body }
  store.push(post)
  return post
}

'use server'

import { revalidateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from '@/app/lib/data'

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string
  const body = formData.get('body') as string

  if (!title || !body) {
    throw new Error('Title and body are required')
  }

  addPost(title, body)

  // Invalidate the "posts" cache tag so the next page load fetches fresh
  // data instead of serving stale cached content.
  revalidateTag('posts')

  // Redirect to the posts page, triggering a server-side render that will
  // call getPosts() — because the "posts" tag was just invalidated, the
  // cache miss forces a fresh data fetch before the page is served.
  redirect('/')
}

