import { revalidateTag, updateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from '@/app/lib/data'

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string
  const body = formData.get('body') as string

  if (!title || !body) {
    throw new Error('Title and body are required')
  }

  addPost(title, body)

  // updateTag invalidates the "posts" cache tag with read-your-own-writes
  // semantics — it immediately expires the cache and marks the route as
  // revalidated, guaranteeing the next render fetches fresh data.
  // In this canary build, revalidateTag requires a second argument (a cache
  // profile string like "max" or a CacheLifeConfig), while updateTag is the
  // idiomatic choice inside a Server Action: single argument, immediate
  // expiration, no deprecation warning.
  updateTag('posts')

  // Redirect to the home page, triggering a server-side render. Because
  // updateTag('posts') just invalidated the cache, the getPosts() call
  // during render will miss the cache and fetch fresh data.
  redirect('/')
}
